<script setup>
import {computed,onMounted,reactive,ref} from 'vue';import AppIcon from '../components/AppIcon.vue';import {adminApi,authToken,get,post,request} from '../services/http';
const PERIODS=[['monthly','月付'],['quarterly','季付'],['half_yearly','半年付'],['yearly','年付'],['two_yearly','两年付'],['three_yearly','三年付'],['onetime','一次性'],['reset_traffic','重置流量']];
const coupons=ref([]),plans=ref([]),loading=ref(false),saving=ref(false),busy=ref(null),showForm=ref(false);const filters=reactive({keyword:'',type:'all',show:'all'}),page=reactive({current:1,size:20,total:0,last:1}),toast=reactive({text:'',type:'success'}),form=reactive(defaultForm());
function localInput(ts){if(!ts)return'';const d=new Date(Number(ts)*1000),x=new Date(d.getTime()-d.getTimezoneOffset()*60000);return x.toISOString().slice(0,16)}function defaultTimes(){const now=new Date(),end=new Date(now.getTime()+30*86400000);const f=d=>{const x=new Date(d.getTime()-d.getTimezoneOffset()*60000);return x.toISOString().slice(0,16)};return[f(now),f(end)]}function defaultForm(){const t=defaultTimes();return{id:null,name:'',code:'',type:1,value_ui:10,started_at:t[0],ended_at:t[1],limit_use:null,limit_use_with_user:1,limit_plan_ids:[],limit_period:[],show:true,batch:false,generate_count:10}}
const displayed=computed(()=>coupons.value.filter(c=>(filters.type==='all'||Number(c.type)===Number(filters.type))&&(filters.show==='all'||Boolean(c.show)===(filters.show==='1'))));const stats=computed(()=>{const now=Date.now()/1000;return{page:coupons.value.length,visible:coupons.value.filter(c=>c.show).length,active:coupons.value.filter(c=>c.show&&Number(c.started_at)<=now&&Number(c.ended_at)>=now).length,expired:coupons.value.filter(c=>Number(c.ended_at)<now).length}});
function notify(text,type='success'){toast.text=text;toast.type=type;clearTimeout(notify.timer);notify.timer=setTimeout(()=>toast.text='',2800)}function makeQuery(){const q=new URLSearchParams({current:String(page.current),pageSize:String(page.size)});if(filters.keyword){q.set('filter[0][id]',/^[A-Za-z0-9]{6,}$/.test(filters.keyword)?'code':'name');q.set('filter[0][value]',filters.keyword)}return q.toString()}
async function load(reset=false){if(reset)page.current=1;loading.value=true;try{const data=await request(`/coupon/fetch?${makeQuery()}`),s=data?.data??data;coupons.value=s?.items||s?.data||(Array.isArray(s)?s:[]);page.total=Number(s?.total||coupons.value.length);page.current=Number(s?.current_page||page.current);page.last=Number(s?.last_page||Math.max(1,Math.ceil(page.total/page.size)))}catch(e){notify(e.message,'error')}finally{loading.value=false}}
async function loadPlans(){try{const d=await get('/plan/fetch');plans.value=Array.isArray(d)?d:[]}catch(e){notify(e.message,'error')}}function create(){Object.assign(form,defaultForm());showForm.value=true}function edit(c){Object.assign(form,defaultForm(),c,{value_ui:Number(c.type)===1?Number(c.value)/100:Number(c.value),started_at:localInput(c.started_at),ended_at:localInput(c.ended_at),limit_plan_ids:[...(c.limit_plan_ids||[])],limit_period:[...(c.limit_period||[])],batch:false,generate_count:10});showForm.value=true}function phase(c){const n=Date.now()/1000;if(!c.show)return['已隐藏','off'];if(Number(c.started_at)>n)return['未开始','waiting'];if(Number(c.ended_at)<n)return['已过期','off'];return['生效中','']};function value(c){return Number(c.type)===1?`减 ¥${(Number(c.value)/100).toFixed(2)}`:`${c.value}% 折扣`}function time(v){return v?new Date(Number(v)*1000).toLocaleString('zh-CN',{hour12:false}):'-'}
function payload(){return{name:form.name.trim(),code:form.code.trim()||undefined,type:Number(form.type),value:Number(form.type)===1?Math.round(Number(form.value_ui)*100):Math.round(Number(form.value_ui)),started_at:Math.floor(new Date(form.started_at).getTime()/1000),ended_at:Math.floor(new Date(form.ended_at).getTime()/1000),limit_use:form.limit_use===''?null:form.limit_use,limit_use_with_user:form.limit_use_with_user===''?null:form.limit_use_with_user,limit_plan_ids:form.limit_plan_ids,limit_period:form.limit_period}}
function validate(){if(!form.name.trim())return'请输入优惠券名称';if(Number(form.value_ui)<=0)return'优惠金额或比例必须大于 0';if(Number(form.type)===2&&Number(form.value_ui)>=100)return'百分比优惠必须小于 100%';if(!form.started_at||!form.ended_at||new Date(form.ended_at)<=new Date(form.started_at))return'结束时间必须晚于开始时间';if(form.batch&&(Number(form.generate_count)<1||Number(form.generate_count)>500))return'批量生成数量必须在 1–500 之间';return''}
async function save(){const err=validate();if(err)return notify(err,'error');saving.value=true;try{if(form.batch){const body={...payload(),generate_count:Number(form.generate_count)};const res=await fetch(adminApi('/coupon/generate'),{method:'POST',headers:{Authorization:`Bearer ${authToken().replace(/^Bearer /,'')}`,'Content-Type':'application/json',Accept:'text/csv'},body:JSON.stringify(body)});if(!res.ok)throw new Error('批量生成失败');const blob=await res.blob(),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`coupons-${Date.now()}.csv`;a.click();URL.revokeObjectURL(url);notify(`已生成 ${form.generate_count} 张并导出 CSV`)}else{const before=new Set(coupons.value.map(c=>c.id));await post('/coupon/generate',{...payload(),id:form.id||undefined});await load();let target=form.id?coupons.value.find(c=>Number(c.id)===Number(form.id)):coupons.value.filter(c=>!before.has(c.id)).sort((a,b)=>b.id-a.id)[0];if(target&&Boolean(target.show)!==Boolean(form.show))await post('/coupon/show',{id:target.id});notify(form.id?'优惠券已更新':'优惠券已创建')}showForm.value=false;await load(form.batch||!form.id)}catch(e){notify(e.message,'error')}finally{saving.value=false}}
async function toggle(c){busy.value=c.id;try{await post('/coupon/show',{id:c.id});c.show=!c.show;notify('展示状态已更新')}catch(e){notify(e.message,'error')}finally{busy.value=null}}async function remove(c){if(!confirm(`确定删除优惠券「${c.name}」(${c.code})？`))return;busy.value=c.id;try{await post('/coupon/drop',{id:c.id});notify('优惠券已删除');await load()}catch(e){notify(e.message,'error')}finally{busy.value=null}}async function copyCode(code){await navigator.clipboard.writeText(code);notify('券码已复制')}
onMounted(()=>Promise.all([load(true),loadPlans()]));
</script>
<template><section class="page-stack"><div class="page-heading page-heading-row"><div><h1>优惠券管理</h1><p>创建金额券和折扣券，限制适用套餐、周期、次数及有效时间。</p></div><button class="btn btn-primary" @click="create"><AppIcon name="Plus" :size="16"/>创建优惠券</button></div><div class="stat-grid coupon-stats"><article class="stat-card"><span>当前页券数</span><strong>{{stats.page}}</strong></article><article class="stat-card"><span>当前页展示</span><strong>{{stats.visible}}</strong></article><article class="stat-card"><span>当前页生效</span><strong>{{stats.active}}</strong></article><article class="stat-card"><span>当前页过期</span><strong>{{stats.expired}}</strong></article></div>
<div class="coupon-toolbar"><label class="filter-input"><span>搜索</span><input v-model.trim="filters.keyword" placeholder="优惠券名称或券码" @keyup.enter="load(true)"/></label><label class="field compact-field"><span>类型</span><select v-model="filters.type"><option value="all">全部类型</option><option value="1">固定金额</option><option value="2">百分比折扣</option></select></label><label class="field compact-field"><span>展示状态</span><select v-model="filters.show"><option value="all">全部状态</option><option value="1">已展示</option><option value="0">已隐藏</option></select></label><button class="btn btn-ghost" @click="load(true)">查询</button><button class="btn btn-ghost" :disabled="loading" @click="load()">刷新</button></div>
<div v-if="loading" class="panel settings-loading">正在加载优惠券…</div><div v-else-if="!displayed.length" class="panel settings-loading">暂无符合条件的优惠券</div><div v-else class="coupon-grid"><article v-for="c in displayed" :key="c.id" class="panel coupon-card"><div class="coupon-card-head"><div><span>{{Number(c.type)===1?'金额券':'折扣券'}}</span><h2>{{c.name}}</h2></div><span class="status-pill" :class="phase(c)[1]">{{phase(c)[0]}}</span></div><button class="coupon-code" title="点击复制" @click="copyCode(c.code)"><code>{{c.code}}</code><AppIcon name="Copy" :size="14"/></button><strong class="coupon-value">{{value(c)}}</strong><div class="coupon-meta"><span>有效期<strong>{{time(c.started_at)}}<br/>至 {{time(c.ended_at)}}</strong></span><span>使用限制<strong>总计 {{c.limit_use||'不限'}} 次 · 每人 {{c.limit_use_with_user||'不限'}} 次</strong></span><span>适用套餐<strong>{{c.limit_plan_ids?.length?`${c.limit_plan_ids.length} 个指定套餐`:'全部套餐'}}</strong></span><span>适用周期<strong>{{c.limit_period?.length?c.limit_period.map(k=>PERIODS.find(p=>p[0]===k)?.[1]||k).join('、'):'全部周期'}}</strong></span></div><div class="coupon-actions"><button class="btn btn-ghost btn-sm" :disabled="busy===c.id" @click="toggle(c)">{{c.show?'隐藏':'展示'}}</button><button class="btn btn-ghost btn-sm" @click="edit(c)">编辑</button><button class="btn btn-danger btn-sm" :disabled="busy===c.id" @click="remove(c)">删除</button></div></article></div><div class="pagination"><span>共 {{page.total}} 条</span><button class="btn btn-ghost btn-sm" :disabled="page.current<=1||loading" @click="page.current--;load()">上一页</button><span>{{page.current}} / {{page.last}}</span><button class="btn btn-ghost btn-sm" :disabled="page.current>=page.last||loading" @click="page.current++;load()">下一页</button></div>
<div v-if="showForm" class="modal-backdrop" @click.self="showForm=false"><section class="modal-card coupon-modal"><div class="panel-head"><div><h2>{{form.id?'编辑优惠券':'创建优惠券'}}</h2><p>金额券单位为元，保存时自动转换；批量生成后自动下载 CSV。</p></div><button class="btn btn-ghost" @click="showForm=false">关闭</button></div><label v-if="!form.id" class="coupon-batch-toggle"><input v-model="form.batch" type="checkbox"/><span><strong>批量生成随机券码</strong><small>最多一次生成 500 张；批量券默认展示。</small></span></label><div class="smart-form"><label class="field field-wide"><span>优惠券名称 *</span><input v-model.trim="form.name" maxlength="100" placeholder="例如：新用户立减券"/></label><label v-if="!form.batch" class="field"><span>券码</span><input v-model.trim="form.code" maxlength="32" placeholder="留空自动生成"/></label><label v-else class="field"><span>生成数量 *</span><input v-model.number="form.generate_count" type="number" min="1" max="500"/></label><label class="field"><span>优惠类型 *</span><select v-model.number="form.type"><option :value="1">固定金额</option><option :value="2">百分比折扣</option></select></label><label class="field"><span>{{form.type===1?'优惠金额（元） *':'优惠比例（%） *'}}</span><input v-model.number="form.value_ui" type="number" min="0.01" :max="form.type===2?99:undefined" :step="form.type===1?'0.01':'1'"/></label><label class="field"><span>开始时间 *</span><input v-model="form.started_at" type="datetime-local"/></label><label class="field"><span>结束时间 *</span><input v-model="form.ended_at" type="datetime-local"/></label><label class="field"><span>总使用次数</span><input v-model.number="form.limit_use" type="number" min="1" placeholder="留空不限制"/></label><label class="field"><span>每用户使用次数</span><input v-model.number="form.limit_use_with_user" type="number" min="1" placeholder="留空不限制"/></label><label v-if="!form.batch" class="field"><span>用户端展示</span><select v-model="form.show"><option :value="true">展示</option><option :value="false">隐藏</option></select></label><label class="field field-wide"><span>限定套餐</span><select v-model="form.limit_plan_ids" multiple><option v-for="p in plans" :key="p.id" :value="p.id">{{p.name}}</option></select><small>不选择表示全部套餐；按住 Ctrl / Command 可多选</small></label><div class="field field-wide"><span>限定周期</span><div class="coupon-periods"><label v-for="p in PERIODS" :key="p[0]"><input v-model="form.limit_period" type="checkbox" :value="p[0]"/>{{p[1]}}</label></div><small>不选择表示全部周期</small></div></div><div class="modal-actions"><button class="btn btn-ghost" @click="showForm=false">取消</button><button class="btn btn-primary" :disabled="saving" @click="save">{{saving?'处理中…':form.batch?'生成并导出':'保存优惠券'}}</button></div></section></div><div v-if="toast.text" class="toast" :class="{error:toast.type==='error'}">{{toast.text}}</div></section></template>
